var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【기록-010】 외부 자료</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS003M0008-25：<color=#ffd34c>【記録-010】 外部資料</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【Record-010】 External Material</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-25: <color=#ffd34c>【記錄-010】 外部材料</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"【AT-0287Y】 관찰일지Ⅲ","JPN":"【 AT-0287Y 】 観察日誌Ⅲ","ENG":"【AT-0287Y】 Observation Log III","TWN":"【AT-0287Y】觀察日誌III"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y는 실험대상 중 가장 순종적입니다.","JPN":"- AT-0287Yは、実験対象のうち最も従順な個体です。","ENG":"- AT-0287Y is the most submissive amongst the experiment subjects.","TWN":"AT-0287Y是實驗對象中最順從的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"- 시설의 불합리한 규칙에 순응하는 모습과 차별적인 대우에 반발하지 않는 태도를 보아, 유년기에 유사한 경험을 한 것으로 추정됩니다.","JPN":"― 施設の不合理な規則にも順応し、差別的な待遇にも反発を示さない態度から見て、幼年期に類似した経験をしているものと思われます。","ENG":"- It is assumed that the subject already has had similar experiences, adapting to the irrational regulations of the facility and remaining docile against discrimination.","TWN":"從遵守設施不合理的規定，以及不反抗差別對待的態度來看，推測幼年期有同樣的經歷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"- 일일 평균 체벌 횟수는 입소 후 0.6회를 유지 중입니다.","JPN":"― 1日の平均体罰回数は、入所以来0.6回を維持しています。","ENG":"- The average daily punishment count is being maintained around 0.6.","TWN":"入所後，每日平均體罰次數維持在0.6次。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0195K가 AT-0287Y에게 지속적인 물리적•언어적 폭력을 가하고 있다는 사실을 확인했습니다.","JPN":"- AT-0195KがAT-0287Yに対して持続的に物理的・言語的暴力を加えている事実を確認しました。","ENG":"- It has been confirmed that AT-0195K is constantly exerting physical and verbal abuse against AT-0287Y.","TWN":"已確認AT-0195K對AT-0287Y施加持續的物理性•語言性暴力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"연구진은 1개체를 소모해서 실험군의 질서를 유지하는 것이 효과적이라고 판단했습니다.","JPN":"― 研究チームは、1個体を消費することで、実験群の秩序を維持することが効果的と判断しました。","ENG":"The researchers have determined that it is best to maintain order by using one of the subjects.","TWN":"研究者認為，消耗一個對象來維持實驗群的秩序是很有效果的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0195K에게 보상으로 <color=#ffd34c>반장</color> 직위를 부여하고 질서 유지를 위임했습니다.","JPN":"- AT-0195Kに報酬として<color=#ffd34c>班長</color>の職位を付与し、秩序維持を委任しました。","ENG":"- AT-0195K was rewarded with the title of <color=#ffd34c>Chief</color>, along with the authority to maintain order.","TWN":"作為給AT-0195K的獎勵，賦予<color=#ffd34c>班長</color>職位，以維持秩序。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"【 AT-0287Y 】 관찰일지Ⅴ","JPN":"【 AT-0287Y 】 観察日誌Ⅴ","ENG":"【AT-0287Y】 Observation Log V","TWN":"【AT-0287Y】觀察日誌V"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0195K가 AT-0287Y에게 가하는 폭력 수위가 연구진의 예상대로 높아지고 있습니다.","JPN":"― AT-0195KがAT-0287Yに加える暴力の度合いが、研究チームの予想通り上昇しています。","ENG":"- The level of violence AT-0195K is exerting upon AT-0287Y has increased as the researchers have predicted.","TWN":"AT-0195K對AT-0287Y的暴力程度，與研究者預想的一樣加深了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"- 기대했던 ███의 발현은 관찰되지 않았습니다. 보다 강한 심리적인 압박이 필요하다고 사료됩니다.","JPN":"― 期待した█████の発現は観察されていません。より強い心理的圧迫が必要と思われます。","ENG":"- There were no expected signs of ███ manifestation. It is assumed to require stronger psychological pressure.","TWN":"未觀測到期許的███表現，看來需增加更強的心理壓迫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0225X가 Q에게 AT-0287Y의 보호 조치를 요구했습니다. AT-0225X는 AT-0287Y가 의존하는 실험대상입니다.","JPN":"- AT-0225XがQにAT-0287Yの保護措置を求めました。AT-0225XはAT-0287Yが依存している実験対象です。","ENG":"- AT-0225X made a request to Q to protect AT-0287Y. AT-0225X is a subject AT-0287Y relies upon.","TWN":"AT-0225X向Q要求AT-0287Y的保護措施。AT-0225X是AT-0287Y依賴的實驗對象。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"【 AT-0287Y 】 관찰일지Ⅵ","JPN":"【 AT-0287Y 】 観察日誌Ⅵ","ENG":"【AT-0287Y】 Observation Log VI","TWN":"【AT-0287Y】觀察日誌VI"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y가 커리큘럼에 적극적으로 참여하기 시작했습니다. 보상으로 체벌 수위를 1단계 하향 조정하고 추이를 관찰 중입니다.","JPN":"- AT-0287Yがカリキュラムに積極的に参加し始めました。報酬として体罰の度合いを1段階引き下げ、推移を観察しています。","ENG":"- AT-0287Y is actively engaging in the curriculum. Progression is being observed after reducing punishment level by 1 as a reward.","TWN":"AT-0287Y開始積極參與課程。作為獎勵，體罰等級下調1個階段，繼續進行觀察。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"- 직접적인 계기는 AT-0147S가 AT-0287Y에 대한 AT-0195K의 사적 체벌을 막은 사건입니다.","JPN":"- 直接の契機は、AT-0147SがAT-0287Yに対するAT-0195Kの私的体罰を制止した事件です。","ENG":"- The direct influence came from AT-0147S stopping AT-0195K from acting violent against AT-0287Y.","TWN":"直接的契機，是AT-0147S阻止了AT-0195K對AT-0287Y的私下體罰事件。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"AT-0195K와 AT-0147S의 충돌을 목격하고 심경의 변화가 일어난 것으로 추정됩니다.","JPN":"- AT-0195KとAT-0147Sの衝突を目撃し、心境の変化が起きたものと思われます。","ENG":"We assume the subject changed after witnessing the clash between AT-0195K and AT-0147S.","TWN":"推測是目擊到AT-0195K和AT-0147S的衝突，心境發生了變化。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y가 일과 중 AT-0147S를 따라다니는 시간이 늘었습니다.","JPN":"- AT-0287Yが日中、AT-0147Sを追いかける時間が増えています。","ENG":"- AT-0287Y is spending more time following around AT-0147S during the day.","TWN":"AT-0287Y在一天中，跟著AT-0147S的時間增加了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"AT-0287Y는 AT-0147S에게 동경심을 표출하면서 사소한 행동도 남의 눈을 피해 흉내 내고 있습니다.","JPN":"- AT-0287YはAT-0147Sに憧れの感情を示し​つつ、些細な行動までも人目を忍び模倣しています。","ENG":"AT-0287Y has shown admiration towards AT-0147S and is secretly mimicking her behavior.","TWN":"AT-0287Y對AT-0147S表現出憧憬的同時，在他人看不到的地方，模仿AT-0147S的行為。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y와 커뮤니케이션을 하면서 ███ 발현의 징후는 사라졌습니다. 연구진은 애석해 하고 있습니다.","JPN":"― AT-0287Yとのコミュニケーションを経て█████発現の兆候は消えました。研究チームは残念がっています。","ENG":"- The signs of ███ manifestation have disappeared after communicating with AT-0287Y. The researchers are unhappy about the change.","TWN":"和AT-0287Y進行交流時，███表現的徵兆消失了。研究者對此表示惋惜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"【 AT-0287Y 】 관찰일지Ⅷ","JPN":"【 AT-0287Y 】 観察日誌Ⅷ","ENG":"【AT-0287Y】 Observation Log VIII","TWN":"【AT-0287Y】觀察日誌Ⅷ"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"- 격리 실험을 허가해 주셔서 감사드립니다.","JPN":"― 隔離実験を許可していただき、感謝申し上げます。","ENG":"- Thank you for giving permission to perform isolation experiments.","TWN":"感謝您許可隔離實驗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y가 실험에 자원한 뒤 처음으로 AT-0225X와 언쟁을 빚었습니다.","JPN":"- AT-0287Yが実験に志願して以来、初めてAT-0225Xとの言い争いが発生しました。","ENG":"- After AT-0287Y volunteered for the experiment, an argument with AT-0225X occurred for the first time.","TWN":"AT-0287Y自願參加實驗後，第一次與AT-0225X發生爭執。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"CCTV 영상 확인 결과, AT-0287Y는 강한 어조로 지원을 만류하는 AT-0225X에게 다음과 같이 대답했습니다.","JPN":"- 監視カメラの映像を確認した結果、AT-0287Yは強い語調で志願を止めさせようとするAT-0225Xに、次のように返答しています。","ENG":"The CCTV recording showed AT-0287Y answering to AT-0225X's persuasion to withdraw from the experiment:","TWN":"確認CCTV影像後，AT-0287Y以強硬的語氣，對挽留她當支援的AT-0225X做了以下的回答。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>나, 난 너보다 나이도 많은데...... 이제 더는 네 뒤에 숨기 싫어......</color>","JPN":"<color=#ffd34c>わ、私、あなたより年上なのに……もうあなたの後ろに隠れるのは嫌……</color>","ENG":"<color=#ffd34c>I-I'm older than you... I don't want to hide behind you any more...</color>","TWN":"<color=#ffd34c>我，我年紀也比妳大……我討厭一直躲在妳後面……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그러니까 나도, 대장처럼 강해질래......</color>","JPN":"<color=#ffd34c>だから私も、隊長のように強くなるの……</color>","ENG":"<color=#ffd34c>I want to become strong like Cap...</color>","TWN":"<color=#ffd34c>所以我也要變得和隊長一樣強大……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그래서...... 그래서 꼭, 나쁜 녀석들을 혼내 줄 거야.</color>","JPN":"<color=#ffd34c>強くなって……それで絶対、悪者たちをこらしめてやるんだから。</color>","ENG":"<color=#ffd34c>And then... And then I'm going to punish the bad guys.</color>","TWN":"<color=#ffd34c>所以……所以，我一定要親手教訓那些壞人。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"【 AT-0287Y 】 관찰일지Ⅸ","JPN":"【 AT-0287Y 】 観察日誌Ⅸ","ENG":"【AT-0287Y】 Observation Log IX","TWN":"【AT-0287Y】觀察日誌Ⅸ"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"- AT-0287Y의 강함에 대한 집념은 놀라울 정도입니다.","JPN":"- AT-0287Yの強さに対する執念は驚嘆に値します。","ENG":"- AT-0287Y's determination towards power is astounding.","TWN":"AT-H0287Y對強大的執著，非常讓人吃驚。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"- 심리적 압박에 의한 ███ 발현은 기대 이상의 성공을 거두었습니다. 골격 구조의 극단적인 변화를 동반한 신체 능력의 증대가 발생했습니다.","JPN":"― 心理的圧迫による█████の発現は期待を上回る成果を上げました。骨格構造の極端な変化を伴う身体能力の増大が発生しています。","ENG":"- The manifestation of ███ caused by psychological pressure was incredibly successful. It resulted in an extreme change in the skeletal structure along with massive physical enhancements.","TWN":"由心理壓迫產生的███表現收到了超乎期待的成果。伴隨骨骼構造的極端變化，身體能力發生增大的情形。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"- 데이터 수집 이후 ███ 발현 억제에 성공했습니다. 지속적인 정신 건강 관리가 필요합니다.","JPN":"― データ収集以降、█████発現の抑制に成功しました。持続的なメンタルヘルスケアが必要です。","ENG":"- Successfully suppressed ███ manifestation after collecting data. Subject requires continuous monitoring of mental health.","TWN":"資料收集後，成功抑制了███表現。需要持續的心理健康治療。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"- 대안인자 적성은 평균 이상으로 나타났습니다. 운이 좋다면 상부에나, 본인에게나 만족스러운 결과를 얻게 되겠죠.","JPN":"― 代案因子適性は平均以上を示しています。運が良ければ、上層部にも本人にも満足のいく結果が得られるでしょう。","ENG":"- Aptitude towards the Alternative Factor was above average. With luck, it could yield satisfying results for both the subject and the superiors.","TWN":"替代因子能力高於平均值。幸運的話，無論是上級還是本人，都可以得到令人滿意的結果。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"《상신》 AT-0195K이 완성형 인자 <color=#ffd34c>나이트</color>의 실험 후보로 선정된다는 소식을 접했습니다. 감독관으로서 상부의 재고를 요청합니다.","JPN":"《上申》 AT-0195Kが完成型因子<color=#ffd34c>ナイト</color>の実験候補に選定されるとの情報を得ました。監督官として上層部に再考を求めます。","ENG":"《Report》 I received news that AT-0195K was selected as the experiment candidate for the Complete Factor, <color=#ffd34c>Knight</color>. As the supervisor, I urge the superiors to reconsider.","TWN":"《報告》 我接到了AT-0195K被選為完全體因子<color=#ffd34c>騎士</color>的實驗候補。作為監督官，請求上級重新考慮。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};